"use client";

import { usePathname } from "next/navigation";
import { useSession, signOut } from "next-auth/react";
import { Menu, LogOut, ChevronDown, Sun, Moon, PanelLeftClose, PanelLeftOpen, ShieldCheck } from "lucide-react";
import { useTheme } from "next-themes";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { getInitials } from "@/lib/utils";


const PAGE_LABELS: Record<string, string> = {
  dashboard:  "Dashboard",
  employees:  "Employees",
  visits:     "All Visits",
  results:    "Lab Results",
  vitals:     "Vital Signs",
  payments:   "Payments",
};

function HrBreadcrumb() {
  const pathname = usePathname();
  const segments = pathname.split("/").filter(Boolean);
  // segments[0] is "hr", segments[1] is the section
  const section = segments[1] ?? "dashboard";
  const label = PAGE_LABELS[section] ?? section;

  return (
    <div className="hidden sm:flex items-center gap-1.5 text-sm">
      <span className="text-muted-foreground/50">HR Portal</span>
      <span className="text-muted-foreground/30">/</span>
      <span className="font-semibold text-foreground">{label}</span>
    </div>
  );
}

interface HrHeaderProps {
  onMenuClick?: () => void;
  sidebarCollapsed?: boolean;
  onToggleCollapse?: () => void;
}

export function HrHeader({ onMenuClick, sidebarCollapsed, onToggleCollapse }: HrHeaderProps) {
  const { data: session } = useSession();
  const { resolvedTheme, setTheme } = useTheme();

  const firstName = session?.user?.firstName ?? "";
  const lastName  = session?.user?.lastName  ?? "";
  const email     = session?.user?.email     ?? "";
  const initials  = firstName && lastName ? getInitials(firstName, lastName) : "HR";

  return (
    <header className="sticky top-0 z-30 flex h-16 items-center gap-3 px-4 shrink-0 border-b border-border bg-card">

      {/* Mobile menu toggle */}
      <Button variant="ghost" size="icon" className="lg:hidden" onClick={onMenuClick}>
        <Menu className="h-5 w-5" />
        <span className="sr-only">Toggle menu</span>
      </Button>

      {/* Desktop sidebar collapse toggle */}
      {onToggleCollapse && (
        <Button
          variant="ghost"
          size="icon"
          className="hidden lg:flex h-8 w-8 rounded-lg"
          onClick={onToggleCollapse}
          aria-label={sidebarCollapsed ? "Expand sidebar" : "Collapse sidebar"}
        >
          {sidebarCollapsed
            ? <PanelLeftOpen  className="h-4 w-4 text-muted-foreground" />
            : <PanelLeftClose className="h-4 w-4 text-muted-foreground" />
          }
        </Button>
      )}

      {/* Breadcrumb */}
      <HrBreadcrumb />

      <div className="flex-1" />

      {/* HR badge */}
      <div className="hidden sm:flex items-center gap-1.5 rounded-full border border-violet-400/25 bg-violet-500/8 px-2.5 py-1">
        <ShieldCheck className="h-3 w-3 text-violet-500 dark:text-violet-400" />
        <span className="text-[10px] font-semibold text-violet-600 dark:text-violet-400 tracking-wide">HR ACCESS</span>
      </div>

      <div className="flex items-center gap-1">

        {/* Theme toggle */}
        <Button
          variant="ghost"
          size="icon"
          className="h-9 w-9 rounded-xl"
          onClick={() => setTheme(resolvedTheme === "dark" ? "light" : "dark")}
          aria-label="Toggle theme"
        >
          <Sun  className="h-4 w-4 rotate-0 scale-100 transition-all duration-300 dark:-rotate-90 dark:scale-0" />
          <Moon className="absolute h-4 w-4 rotate-90 scale-0 transition-all duration-300 dark:rotate-0 dark:scale-100" />
        </Button>

        {/* User dropdown */}
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" className="flex items-center gap-2 h-9 px-2 rounded-xl hover:bg-muted">
              <Avatar className="h-7 w-7 border border-violet-400/30">
                <AvatarFallback className="bg-violet-500/10 text-violet-600 dark:text-violet-400 text-xs font-bold">
                  {initials}
                </AvatarFallback>
              </Avatar>
              <span className="hidden sm:block text-sm font-medium max-w-28 truncate">
                {firstName} {lastName}
              </span>
              <ChevronDown className="h-3.5 w-3.5 text-muted-foreground hidden sm:block" />
            </Button>
          </DropdownMenuTrigger>

          <DropdownMenuContent className="w-56 border-border shadow-(--shadow-lg)" style={{ backgroundColor: "hsl(var(--card))" }} align="end" forceMount>
            <DropdownMenuLabel className="font-normal px-3 py-2.5">
              <div className="flex items-center gap-2.5">
                <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-violet-500/10 border border-violet-400/30 text-xs font-bold text-violet-600 dark:text-violet-400">
                  {initials}
                </div>
                <div className="flex flex-col min-w-0">
                  <p className="text-sm font-semibold leading-none truncate">{firstName} {lastName}</p>
                  <p className="text-xs leading-none text-muted-foreground mt-1 truncate">{email}</p>
                  <p className="text-[10px] leading-none text-violet-500 dark:text-violet-400 mt-1">HR Staff</p>
                </div>
              </div>
            </DropdownMenuLabel>

            <DropdownMenuSeparator />

            <DropdownMenuItem
              className="cursor-pointer text-destructive focus:text-destructive focus:bg-destructive/10 gap-2"
              onClick={() => signOut({ callbackUrl: "/login?portal=hr" })}
            >
              <LogOut className="h-4 w-4" />
              <span>Sign out</span>
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
    </header>
  );
}
