"use client";

import { useState } from "react";
import { HrSidebar } from "@/components/hr/hr-sidebar";
import { HrHeader } from "@/components/hr/hr-header";

export default function HrLayout({ children }: { children: React.ReactNode }) {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);

  return (
    <div className="hr-portal flex h-screen overflow-hidden bg-background">
      <HrSidebar
        isOpen={sidebarOpen}
        onClose={() => setSidebarOpen(false)}
        collapsed={sidebarCollapsed}
        onToggleCollapse={() => setSidebarCollapsed((c) => !c)}
      />

      <div className="flex flex-1 flex-col overflow-hidden transition-all duration-300">
        <HrHeader
          onMenuClick={() => setSidebarOpen(true)}
          sidebarCollapsed={sidebarCollapsed}
          onToggleCollapse={() => setSidebarCollapsed((c) => !c)}
        />
        <main className="flex-1 overflow-y-auto scrollbar-thin bg-(--surface-1)">
          <div className="mx-auto px-4 sm:px-6 py-6 max-w-7xl animate-slide-up">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
}
